gcode_macro M600.gcode:
{% set X = params.X|default(0)|float %}
{% set Y = params.Y|default(-80)|float %}
{% set RETRACT = params.RETRACT|default(800)|float %}
{% set current_z = printer.toolhead.position.z %}


{% set old_filament = printer.save_variables.variables.last_filament|default("PLA") %}


{% set new_raw = params.FILAMENT|default(old_filament) %}
{% set new_filament = (new_raw if new_raw|string != "" else old_filament)|string|upper %}


{% set old_temp = 215 %}
{% if old_filament == "PETG" %}{% set old_temp = 240 %}
{% elif old_filament == "ABS" or old_filament == "ASA" %}{% set old_temp = 245 %}
{% elif old_filament == "TPU" or old_filament == "FLEX" %}{% set old_temp = 230 %}
{% endif %}

{% set new_temp = 215 %}
{% if new_filament == "PETG" %}{% set new_temp = 240 %}
{% elif new_filament == "ABS" or new_filament == "ASA" %}{% set new_temp = 245 %}
{% elif new_filament == "TPU" or new_filament == "FLEX" %}{% set new_temp = 230 %}
{% endif %}


SET_GCODE_VARIABLE MACRO=_PAUSE_STATE VARIABLE=filament_changed VALUE=1

PAUSE


M109 S{old_temp}


G91
G1 E-2 F2700
G90


{% if current_z > 100 %}
G1 Z80 F1200
{% else %}
G91
G1 Z20 F600
G90
{% endif %}


G1 X{X} Y{Y} F6000


G91
G1 E-{RETRACT} F600
G90


M104 S{new_temp}


SAVE_VARIABLE VARIABLE=last_filament VALUE='"{new_filament}"'
SAVE_VARIABLE VARIABLE=last_extruder_temp VALUE={new_temp}

{% if old_filament != new_filament %}
RESPOND TYPE=command MSG="Schimba din {old_filament} ({old_temp}C) in {new_filament} ({new_temp}C). Apasa RESUME cand e gata."
{% else %}
RESPOND TYPE=command MSG="Schimba filament {new_filament}. Apasa RESUME cand e gata."
{% endif %}

